return [
  {
    json: {
      requestId: 'manual-forge-' + Date.now(),
      prompt: 'Transforma el pedido en un workflow operable, corto y gratis.',
      requestedBy: 'ARIA',
      source: 'manual',
      freeOnly: true,
    },
  },
];

const payload = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const rawPrompt = String(payload.prompt ?? payload.message ?? payload.task ?? '').trim();
const prompt = rawPrompt || 'Transforma el pedido en un workflow operable, corto y gratis.';
return [
  {
    json: {
      requestId: payload.requestId ?? 'req-' + Date.now(),
      workflow: 'Oracle AI - FORGE',
      agentId: 'FORGE',
      role: 'Automatizacion y operaciones',
      specialty: 'Baja la idea a workflows, integraciones y pasos operativos.',
      prompt,
      requestedBy: String(payload.requestedBy ?? 'ARIA'),
      source: payload.source ?? ($json.body ? 'webhook' : 'workflow'),
      cutoffReason: payload.cutoffReason ?? 'not-needed',
      executionOrder: payload.executionOrder ?? [],
      tieBreakerContext: payload.tieBreakerContext ?? null,
      freeOnly: true,
    },
  },
];

const prompt = $json.prompt ?? '';
const compactTask = prompt.length > 140 ? prompt.slice(0, 137) + '...' : prompt;
return {
  json: {
    ...$json,
    task: compactTask,
    thought: 'FORGE reviso el pedido y produjo una salida corta y accionable.',
    message: 'FORGE recomienda ejecutar un frente puntual alineado con su especialidad.',
    findings: [
      'FORGE detecto una oportunidad clara vinculada al pedido',
      'FORGE sugiere mantener foco en una sola decision por iteracion',
    ],
    risks: [
      'FORGE marco una dependencia o supuesto a validar',
    ],
    nextSteps: [
      'FORGE propone un siguiente paso corto y medible',
      'Cerrar con sintesis desde ARIA',
    ],
    latencyMs: 900,
    cutoffReason: $json.cutoffReason ?? 'not-needed',
    executionOrder: $json.executionOrder ?? [],
    tieBreakerContext: $json.tieBreakerContext ?? null,
  },
};
